              >
                <Text style={{ fontSize: 11 }}>📁</Text>
                <Text
                  style={{
                    color: AC.secondaryLabel,
                    fontSize: 12,
                    fontFamily: Platform.OS === "ios" ? "Menlo" : "monospace",
                    maxWidth: 220,
                  }}
                  numberOfLines={1}
                >
                  {thread.workDir.split("/").filter(Boolean).pop() ?? thread.workDir}
                </Text>
                {messages.length === 0 && (
                  <IconSymbol
                    name="chevron.down"
                    size={10}
                    color={AC.secondaryLabel as any}
                  />
                )}
              </View>
            </TouchableBounce>
          ) : null}

          <View
            style={{
              flexDirection: "row",
              alignItems: "flex-end",
              gap: SPACING.sm,
              backgroundColor: isDark ? "#1c1c1e" : "#fff",
              borderRadius: 22,
              borderWidth: 1,
              borderColor: isDark ? "rgba(255,255,255,0.08)" : AC.separator,
              paddingHorizontal: SPACING.md,
              paddingVertical: SPACING.xs,
              ...SHADOW.sm,
            }}
          >
            <TextInput
              placeholder="Message…"
              placeholderTextColor={AC.systemGray3}
              value={input}
              onChangeText={handleInputChange}
              multiline
              style={{
                minHeight: 40,
                maxHeight: 120,
                color: AC.label,
                fontSize: TYPOGRAPHY.fontSizes.md,
                lineHeight: TYPOGRAPHY.lineHeights.md,
                paddingVertical: SPACING.sm,
                flex: 1,
              }}
            />
            <TouchableBounce
              sensory
              disabled={!input.trim() || sending}
              onPress={send}
              style={{
                opacity: !input.trim() || sending ? 0.3 : 1,
                marginBottom: SPACING.xs,
              }}
            >
              <View
                style={{
                  width: 32,
                  height: 32,
                  borderRadius: 16,
                  backgroundColor: input.trim() ? AC.label : (isDark ? "rgba(255,255,255,0.12)" : "rgba(0,0,0,0.08)"),
                  justifyContent: "center",
                  alignItems: "center",
                }}
              >
                <IconSymbol
                  name="arrow.up"
                  size={14}
