              </View>
            </TouchableBounce>
          </View>
        </View>
      </View>

      {/* Directory browser — only available on turn 0 */}
      <DirectoryBrowser
        visible={showDirBrowser}
        onSelect={(path) => {
          setShowDirBrowser(false);
          if (id) actions.updateThreadWorkDir(id, path).catch(() => {});
        }}
        onCancel={() => setShowDirBrowser(false)}
      />

      <BottomSheetModal
        ref={terminalRef}
        snapPoints={["40%", "70%"]}
