          </View>
          <View
            style={{
              flex: 1,
              backgroundColor: "#0a0a0a",
              borderRadius: BORDER_RADIUS.lg,
              padding: SPACING.md,
              gap: SPACING.xs,
            }}
          >
            <FlatList
              data={terminalLines}
              keyExtractor={(_, index) => `${index}`}
              renderItem={({ item }) => (
                <Text
                  style={{
                    color: "#a8e6a8",
                    fontFamily: Platform.select({
                      ios: "Menlo",
                      android: "monospace",
