/** iMessage-style three bouncing dots */
function BouncingDots({ color }: { color: string }) {
  const d1 = useRef(new Animated.Value(0)).current;
  const d2 = useRef(new Animated.Value(0)).current;
  const d3 = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    // Animated.delay is NOT compatible with useNativeDriver:true — use setTimeout
    // to stagger each dot's independent loop instead.
    const makeBounce = (val: Animated.Value) =>
      Animated.loop(
        Animated.sequence([
          Animated.timing(val, { toValue: -5, duration: 260, useNativeDriver: true }),
          Animated.timing(val, { toValue: 0,  duration: 260, useNativeDriver: true }),
        ])
      );

    const anim1 = makeBounce(d1);
    anim1.start();

    const animRefs: Animated.CompositeAnimation[] = [anim1];
    const t1 = setTimeout(() => { const a = makeBounce(d2); a.start(); animRefs.push(a); }, 150);
    const t2 = setTimeout(() => { const a = makeBounce(d3); a.start(); animRefs.push(a); }, 300);

    return () => {
      animRefs.forEach((a) => a.stop());
      clearTimeout(t1);
      clearTimeout(t2);
    };
  }, []);

  const dot = (val: Animated.Value) => (
    <Animated.View
      style={{
        width: 7, height: 7, borderRadius: 3.5,
        backgroundColor: color,
        transform: [{ translateY: val }],
      }}
    />
  );
  return (
    <View style={{ flexDirection: "row", gap: 5, alignItems: "center" }}>
      {dot(d1)}{dot(d2)}{dot(d3)}
    </View>
  );
}

function ThinkingIndicator({
  status,
  toolSteps,
  permissionRequests,
  onApprove,
  onDeny,
  isDark,
}: {
  status: ThreadStatus;
  toolSteps: ToolStep[];
  permissionRequests: PermissionRequest[];
  onApprove: (id: string) => void;
  onDeny: (id: string) => void;
  isDark: boolean;
}) {
  // Show the most recent steps (last 6), newest at the bottom
  const visibleSteps = toolSteps.slice(-6);
  const hasRunningStep = visibleSteps.some((s) => s.status === "running");
  const dotColor = isDark ? "rgba(255,255,255,0.45)" : "rgba(0,0,0,0.35)";

  const bubbleBg  = isDark ? "#1c1c1e" : "#fff";
  const bubbleBorder = isDark ? "rgba(255,255,255,0.07)" : "rgba(0,0,0,0.08)";

  return (
    <View style={{ gap: 10, paddingTop: SPACING.xs }}>

      {/* ── Unified acting bubble ─────────────────────────── */}
      <View
        style={{
          alignSelf: "flex-start",
          backgroundColor: bubbleBg,
          borderRadius: BORDER_RADIUS.xl,
          borderBottomLeftRadius: SPACING.xs,
          borderWidth: 1,
          borderColor: bubbleBorder,
          paddingHorizontal: 14,
          paddingVertical: 11,
          gap: 7,
          minWidth: 72,
          ...SHADOW.sm,
        }}
      >
        {/* Tool step rows */}
        {visibleSteps.map((step) => {
          const meta = TOOL_META[step.tool] ?? TOOL_META.unknown;
          const isRunning = step.status === "running";
          const isError   = step.status === "error";
          const rowColor  = isRunning ? meta.color : isError ? "#EF4444" : (isDark ? "rgba(255,255,255,0.28)" : "rgba(0,0,0,0.28)");

          return (
            <View
              key={step.id}
              style={{ flexDirection: "row", alignItems: "center", gap: 7 }}
            >
              {/* Status badge */}
              {isRunning ? (
                <ActivityIndicator size="small" color={meta.color} style={{ width: 14, height: 14 }} />
              ) : isError ? (
                <IconSymbol name="xmark.circle.fill" size={13} color="#EF4444" />
              ) : (
                <IconSymbol name="checkmark.circle.fill" size={13} color="#22C55E" />
              )}

              {/* Tool icon */}
              <View
                style={{
                  width: 20, height: 20, borderRadius: 5,
                  backgroundColor: isRunning ? `${meta.color}20` : (isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.05)"),
                  justifyContent: "center", alignItems: "center",
                }}
              >
                <IconSymbol name={meta.icon as any} size={11} color={isRunning ? meta.color : rowColor} />
              </View>

              {/* Label */}
              <Text
                style={{
                  color: isRunning ? AC.label : (isDark ? "rgba(255,255,255,0.4)" : "rgba(0,0,0,0.38)"),
                  fontSize: 12.5,
                  fontWeight: isRunning ? "500" : "400",
                  fontFamily: Platform.OS === "ios" ? "Menlo" : "monospace",
                  flexShrink: 1,
                }}
                numberOfLines={1}
              >
                {step.label}
              </Text>
            </View>
          );
        })}

        {/* Bouncing dots — shown when there are no running steps (waiting for next action) */}
        {!hasRunningStep && (
          <BouncingDots color={dotColor} />
        )}
      </View>

      {/* ── Permission request cards ───────────────────────── */}
      {permissionRequests.map((req) => {
        const meta = TOOL_META[req.tool] ?? TOOL_META.unknown;
        return (
          <View
            key={req.id}
            style={{
              backgroundColor: bubbleBg,
              borderRadius: BORDER_RADIUS.lg,
              borderWidth: 1.5,
              borderColor: AC.systemOrange,
              overflow: "hidden",
              ...SHADOW.sm,
            }}
          >
            {/* Orange header strip */}
            <View
              style={{
                flexDirection: "row",
                alignItems: "center",
                gap: 7,
                backgroundColor: isDark ? "rgba(255,149,0,0.15)" : "rgba(255,149,0,0.10)",
                paddingHorizontal: 14,
                paddingVertical: 9,
              }}
            >
              <View
                style={{
                  width: 24, height: 24, borderRadius: 7,
                  backgroundColor: "rgba(255,149,0,0.20)",
                  justifyContent: "center", alignItems: "center",
                }}
              >
                <IconSymbol name={meta.icon as any} size={13} color={AC.systemOrange} />
              </View>
              <Text style={{ color: AC.systemOrange, fontSize: 13, fontWeight: "700", flex: 1 }}>
                Permission Required
              </Text>
              <IconSymbol name="exclamationmark.triangle.fill" size={13} color={AC.systemOrange} />
            </View>

            {/* Description + buttons */}
            <View style={{ padding: 14, gap: 12 }}>
              <Text
                style={{
                  color: AC.label,
                  fontSize: 13,
                  lineHeight: 18,
                  fontFamily: req.tool === "bash" ? (Platform.OS === "ios" ? "Menlo" : "monospace") : undefined,
                }}
              >
                {req.description}
              </Text>
              <View style={{ flexDirection: "row", gap: SPACING.sm }}>
                <TouchableBounce sensory onPress={() => onApprove(req.id)} style={{ flex: 1 }}>
                  <View
                    style={{
                      backgroundColor: AC.systemBlue,
                      borderRadius: BORDER_RADIUS.md,
                      paddingVertical: 9,
                      alignItems: "center",
                    }}
                  >
                    <Text style={{ color: "#fff", fontSize: 14, fontWeight: "600" }}>Allow</Text>
                  </View>
                </TouchableBounce>
                <TouchableBounce sensory onPress={() => onDeny(req.id)} style={{ flex: 1 }}>
                  <View
                    style={{
                      backgroundColor: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)",
                      borderRadius: BORDER_RADIUS.md,
                      paddingVertical: 9,
                      alignItems: "center",
                    }}
                  >
                    <Text style={{ color: AC.label, fontSize: 14, fontWeight: "600" }}>Deny</Text>
                  </View>
                </TouchableBounce>
              </View>
            </View>
          </View>
        );
      })}
    </View>
  );
